import sys
import heapq

def main():
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    M = int(data[1])
    X = int(data[2])

    original_adj = [[] for _ in range(N + 1)]
    reversed_adj = [[] for _ in range(N + 1)]

    index = 3
    for _ in range(M):
        u = int(data[index])
        v = int(data[index + 1])
        original_adj[u].append(v)
        reversed_adj[v].append(u)
        index += 2

    INF = float('inf')
    dist = [INF] * (2 * (N + 1))  # dist[i][0] for normal, dist[i][1] for reversed

    heap = []
    dist[1] = 0
    heapq.heappush(heap, (0, 1, 0))  # (cost, node, mode)

    while heap:
        cost, u, mode = heapq.heappop(heap)

        if u == N:
            break

        if cost > dist[u + mode * N]:
            continue

        # Move along current mode edges
        if mode == 0:
            for v in original_adj[u]:
                if dist[v] > cost + 1:
                    dist[v] = cost + 1
                    heapq.heappush(heap, (dist[v], v, 0))
        else:
            for v in reversed_adj[u]:
                if dist[v + N] > cost + 1:
                    dist[v + N] = cost + 1
                    heapq.heappush(heap, (dist[v + N], v, 1))

        # Reverse the edges (cost X), and move along new edges
        new_mode = 1 - mode
        reverse_cost = cost + X
        if mode == 0:
            for v in original_adj[u]:
                if dist[v + N] > reverse_cost:
                    dist[v + N] = reverse_cost
                    heapq.heappush(heap, (dist[v + N], v, new_mode))
        else:
            for v in reversed_adj[u]:
                if dist[v] > reverse_cost:
                    dist[v] = reverse_cost
                    heapq.heappush(heap, (dist[v], v, new_mode))

    result = min(dist[N], dist[N + N])
    print(result)

if __name__ == "__main__":
    main()
